```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);

    // Read packet_id using span() for zero-copy view
    auto packet_id_span = adaptor.span(4);
    uint32_t packet_id = 0;
    std::memcpy(&packet_id, packet_id_span.data(), 4);

    // Read username using prefixed adaptor
    std::string username;
    adaptor >> hexi::prefixed(username);

    // Read scores vector using prefixed adaptor with container reading
    std::vector<uint32_t> scores;
    adaptor >> hexi::prefixed(scores);

    // Read metadata string using null_terminated adaptor
    std::string metadata;
    adaptor >> hexi::null_terminated(metadata);

    // Skip remaining padding bytes if any
    // Calculate remaining bytes and skip them
    size_t total_read = 4 + username.size() + sizeof(uint32_t) + scores.size() * sizeof(uint32_t) + metadata.size() + 1;
    size_t padding = buffer.size() - total_read;
    if (padding > 0) {
        adaptor.skip(padding);
    }

    return {packet_id, username, scores, metadata};
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);

    // Use span() to get zero-copy view of packet_id
    auto packet_id_span = adaptor.span(4);
    uint32_t packet_id = 0;
    std::memcpy(&packet_id, packet_id_span.data(), 4);

    // Read username using prefixed adaptor to get string_view
    std::string_view username;
    adaptor >> hexi::prefixed(username);

    // Skip the scores vector by reading count then skipping data
    uint32_t scores_count = 0;
    adaptor >> scores_count;
    adaptor.skip(scores_count * sizeof(uint32_t));

    return {packet_id, username};
}
```

## Key Implementation Points:

### `deserialize_packet` Function:
1. **Packet ID Reading**: Used `span(4)` to create a zero-copy view of the first 4 bytes
2. **Username Reading**: Used `prefixed` adaptor which automatically handles length-prefixed strings
3. **Scores Reading**: Used `prefixed` adaptor with container reading to handle the vector serialization
4. **Metadata Reading**: Used `null_terminated` adaptor for zero-copy string reading
5. **Padding Handling**: Calculated remaining bytes and used `skip()` to handle padding

### `extract_packet_info` Function:
1. **Packet ID Extraction**: Used `span(4)` for zero-copy view
2. **Username Extraction**: Used `prefixed` adaptor to get string_view without copying
3. **Score Skipping**: Read the count then used `skip()` to bypass all score data efficiently

