    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    // Get readable data size using size() function
    size_t readable_size = storage.size();

    // Calculate free space as block_size minus readable data size
    size_t free_space = block_size - readable_size;

    return {readable_size, free_space};
}

