struct UnderrunInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t buff_size;
    bool occurred;
};

UnderrunInfo catch_buffer_underrun() {
    try {
        // This function is called when an exception is caught, so we need to simulate
        // catching a buffer_underrun exception. In practice, this would be called
        // from the exception handler.
        throw; // Re-throw the caught exception
    } catch (const hexi::buffer_underrun& ex) {
        // Extract information from the exception object
        UnderrunInfo info;
        info.read_size = ex.read_size;
        info.total_read = ex.total_read;
        info.buff_size = ex.buff_size;
        info.occurred = true;
        return info;
    }
}

UnderrunInfo safe_read_with_underrun_check(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* destination, std::size_t length) {
    // Create a buffer_adaptor instance from the provided buffer
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    try {
        // Attempt to read data from the buffer
        adaptor.read(destination, length);
        return UnderrunInfo{0, 0, 0, false}; // Read successful, no underrun
    } catch (const hexi::buffer_underrun& ex) {
        // Handle buffer_underrun exception by calling catch_buffer_underrun
        return catch_buffer_underrun();
    }
}
```

