#include <cstdint>

struct ReadLimitInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info{0, 0, 0, false};

    try {
        // This would be where the exception is thrown in real usage
        // For this function, we'll simulate catching the exception
        throw; // Re-throw the caught exception
    } catch (const hexi::stream_read_limit& ex) {
        // Extract exception information using what() method
        auto msg = ex.what();

        // Parse the exception message to extract the three values
        // The message format is: "read_size: X, total_read: Y, read_limit: Z"
        // We can use string manipulation to extract the numbers

        // Split the message into parts
        std::string_view msg_sv(msg);
        auto pos1 = msg_sv.find_first_of(',');
        auto pos2 = msg_sv.find_first_of(',', pos1 + 1);

        if (pos1 != std::string_view::npos && pos2 != std::string_view::npos) {
            info.read_size = std::stoul(std::string(msg_sv.substr(0, pos1)));
            info.total_read = std::stoul(std::string(msg_sv.substr(pos1+2, pos2 - pos1 - 2)));
            info.read_limit = std::stoul(std::string(msg_sv.substr(pos2+2)));
        }

        info.occurred = true;
    }

    return info;
}

ReadLimitInfo safe_read_with_limit_check(hexi::pmc::binary_stream& stream, void* destination, std::size_t length) {
    ReadLimitInfo info{0, 0, 0, false};

    try {
        // Attempt to read from the stream
