        // Read pressure and convert from little-endian using little_to_native_inplace
        adaptor >> pressure;
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create buffer and binary_stream
    std::vector<uint8_t> buffer;
    hexi::binary_stream<std::vector<uint8_t>> adaptor(buffer);

    // Serialize the data
    data.serialise(adaptor);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData result;

    // Create binary_stream from buffer
    hexi::binary_stream<const uint8_t> adaptor(buffer);

    // Deserialize the data
    result.deserialise(adaptor);

    return result;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;

    // Create binary_stream for extraction
    hexi::binary_stream<const uint8_t> adaptor(buffer);

    // Extract sensor name using view
    std::string_view name = adaptor.view();

    // Check bounds for sensor_id
    adaptor.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id
    adaptor >> info.sensor_id;

    // Skip remaining data
    adaptor.skip(std::numeric_limits<size_t>::max());

    info.sensor_name = name;
    return info;
}
